import React, { useState, useEffect } from "react";
import { useAuth } from '../context/AuthContext'; // ajuste o caminho conforme seu projeto

export default function FormTratamento({
  denteSelecionado,
  regiaoSelecionada,
  onAdicionarTratamento,
}) {
  const { user } = useAuth();
  const [tratamento, setTratamento] = useState("");
  const [regiao, setRegiao] = useState(regiaoSelecionada || "");
  const [dente, setDente] = useState(denteSelecionado || "");

  // Atualiza dente/região quando selecionado no odontograma
  useEffect(() => {
    setDente(denteSelecionado || "");
  }, [denteSelecionado]);
  useEffect(() => {
    setRegiao(regiaoSelecionada || "");
  }, [regiaoSelecionada]);

  function handleSubmit(e) {
    e.preventDefault();
    if (!tratamento || !dente || !regiao) return;
    onAdicionarTratamento({
      tratamento,
      dente,
      regiao,
      profissional: user?.nome || "",
      status: "aberto",
      criadoEm: new Date().toISOString(),
      id: Math.random().toString(36).slice(2),
    });
    setTratamento("");
    // Mantém dente e profissional para adicionar vários tratamentos no mesmo dente
    setRegiao("");
  }

  return (
    <form onSubmit={handleSubmit} className="bg-gray-50 p-4 rounded shadow mb-4">
      <div className="flex flex-wrap gap-4 mb-2 items-end">
        <div>
          <label className="text-xs text-gray-500">Tratamento*</label>
          <input
            name="tratamento"
            className="block w-48 border rounded px-2 py-1"
            value={tratamento}
            onChange={e => setTratamento(e.target.value)}
            required
            autoFocus
            placeholder="Descreva o tratamento"
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Região*</label>
          <select
            name="regiao"
            className="block w-28 border rounded px-2 py-1"
            value={regiao}
            onChange={e => setRegiao(e.target.value)}
            required
          >
            <option value="">Selecione</option>
            <option value="Coroa">Coroa</option>
            <option value="Vestibular">Vestibular</option>
            <option value="Palatina">Palatina</option>
            <option value="Lingual">Lingual</option>
            <option value="Mesial">Mesial</option>
            <option value="Distal">Distal</option>
            {/* adicione outras regiões se desejar */}
          </select>
        </div>
        <div>
          <label className="text-xs text-gray-500">Dente*</label>
          <input
            name="dente"
            className="block w-16 border rounded px-2 py-1 bg-gray-100"
            value={dente}
            readOnly
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Profissional</label>
          <input
            name="profissional"
            className="block w-44 border rounded px-2 py-1 bg-gray-100"
            value={user?.nome || ""}
            readOnly
            disabled
          />
        </div>
        <button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded font-semibold"
        >
          Adicionar
        </button>
      </div>
    </form>
  );
}
